import React from 'react';
import type { TooltipPlacement } from '../tooltip';
import type { SliderMarksOption } from './interface';
import './style';
/**
 * 单滑块 Slider 和双滑块共有的属性和方法
 * @public
 */
export interface SliderBaseProps {
    reverse?: boolean;
    /**
     * 最小值
     */
    min?: number;
    /**
     * 最大值
     */
    max?: number;
    /**
     * 步长，取值必须大于 0，并且可被 (max - min) 整除。
     * 当marks不为空对象时，可以设置step为 null，此时 Slider 的可选值仅有 marks 标出来的部分
     */
    step?: null | number;
    /**
     * 刻度标记，key 的类型必须为 `number` 且取值在闭区间 [min, max] 内，每个标签可以单独设置样式
     */
    marks?: SliderMarksOption;
    /**
     * 是否只能拖拽到刻度上
     */
    dots?: boolean;
    /**
     * `marks` 不为空对象时有效，值为 true 时表示值为包含关系，false 表示并列
     */
    included?: boolean;
    /**
     * 值为 true 时，滑块为禁用状态
     */
    disabled?: boolean;
    /**
     * 值为 true 时，Slider 为垂直方向
     */
    vertical?: boolean;
    /**
     * Slider 会把当前值传给tipFormatter，并在 Tooltip 中显示tipFormatter的返回值，若为 null，则隐藏 Tooltip
     */
    tipFormatter?: null | ((value?: number) => React.ReactNode);
    className?: string;
    id?: string;
    style?: React.CSSProperties;
    /**
     * 值为 true 时，Tooltip 将会始终显示；否则始终不显示，哪怕在拖拽及移入时
     */
    tooltipVisible?: boolean;
    /**
     * 设置 Tooltip 展示位置。参考 [Tooltip](/develop/react/slider)
     */
    tooltipPlacement?: TooltipPlacement;
    /**
     * Tooltip 渲染父节点，默认渲染到 body 上
     */
    getTooltipPopupContainer?: (triggerNode: HTMLElement) => HTMLElement;
    /**
     * 是否自动 Focus
     */
    autoFocus?: boolean;
}
/**
 * 单滑块 Slider 独有的属性和方法
 * @public
 */
export interface SliderSingleProps extends SliderBaseProps {
    /**
     * 是否为双滑块模式
     */
    range?: false;
    /**
     * 当前取值
     */
    value?: number;
    /**
     * 初始值
     */
    defaultValue?: number;
    /**
     * 当值发生改变时，会触发 `onChang` 事件，并把改变后的值作为参数传入
     */
    onChange?: (value: number) => void;
    /**
     * 与onmouseup触发时机一致，把当前值作为参数传入
     */
    onAfterChange?: (value: number) => void;
    /**
     * 滑块的样式
     */
    handleStyle?: React.CSSProperties;
    /**
     * 轨道的样式
     */
    trackStyle?: React.CSSProperties;
}
/**
 * 双滑块 Slider 独有的属性和方法
 * @public
 */
export interface SliderRangeProps extends SliderBaseProps {
    /**
     * 是否为双滑块模式
     */
    range: true;
    /**
     * 当前取值
     */
    value?: [number, number];
    /**
     * 初始值
     */
    defaultValue?: [number, number];
    /**
     * 当值发生改变时，会触发 `onChang` 事件，并把改变后的值作为参数传入
     */
    onChange?: (value: [number, number]) => void;
    /**
     * 与onmouseup触发时机一致，把当前值作为参数传入
     */
    onAfterChange?: (value: [number, number]) => void;
    /**
     * 滑块的样式
     */
    handleStyle?: React.CSSProperties[];
    /**
     * 轨道的样式
     */
    trackStyle?: React.CSSProperties[];
}
/**
 * @public
 */
export type SliderProps = SliderSingleProps | SliderRangeProps;
export declare const Slider: React.FC<SliderProps>;
export type { SliderMarksOption } from './interface';
